mapper.select:
SELECT t.*, m.category AS category, c.category_name AS category_name,
       m.model_name AS process_name, COALESCE(NULLIF(m.model_name, ''), t.process_def_key) AS process_definition_name
FROM sys_flow_task t
LEFT JOIN sys_flow_model m ON t.process_def_key = m.model_key
LEFT JOIN sys_flow_category c ON c.id = m.category OR c.category_code = m.category

    AND t.assignee = #{userId}
    AND t.status IN (2, 3, 4, 5, 7, 8)

        AND t.title LIKE CONCAT('%', #{title}, '%')


        AND (
            m.category = #{category}
            OR EXISTS (
                SELECT 1
                FROM sys_flow_category fc
                JOIN sys_flow_category selected ON selected.id = #{category} OR selected.category_code = #{category}
                WHERE (fc.id = m.category OR fc.category_code = m.category)
                  AND (fc.id = selected.id OR fc.ancestors LIKE CONCAT('%', selected.id, '/%'))
            )
        )


        AND t.status = #{status}


ORDER BY t.complete_time DESC

SELECT t.*, m.category AS category, c.category_name AS category_name,
       m.model_name AS process_name, COALESCE(NULLIF(m.model_name, ''), t.process_def_key) AS process_definition_name
FROM sys_flow_task t
LEFT JOIN sys_flow_model m ON t.process_def_key = m.model_key
LEFT JOIN sys_flow_category c ON c.id = m.category OR c.category_code = m.category

    AND t.start_user_id = #{userId}

        AND t.title LIKE CONCAT('%', #{title}, '%')


        AND (
            m.category = #{category}
            OR EXISTS (
                SELECT 1
                FROM sys_flow_category fc
                JOIN sys_flow_category selected ON selected.id = #{category} OR selected.category_code = #{category}
                WHERE (fc.id = m.category OR fc.category_code = m.category)
                  AND (fc.id = selected.id OR fc.ancestors LIKE CONCAT('%', selected.id, '/%'))
            )
        )


        AND t.status = #{status}


ORDER BY t.create_time DESC

SELECT COUNT(1)
FROM sys_flow_task t
WHERE t.assignee = #{userId}
  AND t.status IN (2, 3, 4, 5, 7, 8)
  AND t.complete_time >= #{since}
